var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var offsetX = GetFloat(parameters, "offsetX", 0.5f);
        var offsetY = GetFloat(parameters, "offsetY", 0.5f);
        var rotation = GetFloat(parameters, "rotation", 0f) * MathF.PI / 180f;
        var mirrorH = GetBool(parameters, "mirrorH");
        var mirrorV = GetBool(parameters, "mirrorV");

        var w = input.Width;
        var h = input.Height;
        var dx = (int)MathF.Round(offsetX * w);
        var dy = (int)MathF.Round(offsetY * h);
        var cosR = MathF.Cos(rotation);
        var sinR = MathF.Sin(rotation);

        var result = new PixelBuffer(w, h);

        result.ParallelForEachPixel((x, y) =>
        {
            var sx = x;
            var sy = y;

            // Mirror
            if (mirrorH) sx = w - 1 - sx;
            if (mirrorV) sy = h - 1 - sy;

            // Rotation around center
            if (MathF.Abs(rotation) > 0.001f)
            {
                var cx = sx - w * 0.5f;
                var cy = sy - h * 0.5f;
                sx = (int)MathF.Round(cx * cosR + cy * sinR + w * 0.5f);
                sy = (int)MathF.Round(-cx * sinR + cy * cosR + h * 0.5f);
            }

            var (r, g, b, a) = input.GetPixelWrapped(sx + dx, sy + dy);
            result.SetPixel(x, y, r, g, b, a);
        });

        return result;
}
